9	// reviewPromptDecorator wraps a graphql.ReviewSessionService so each Respond
10	// renders the structured review-session prompt that would be sent to the
11	// reviewer harness and prepends a short pinned-section preview onto the
12	// synthetic reviewer reply. The underlying service still owns session state
13	// and event publication; this decorator only ensures the prompt renderer is
14	// exercised on every live Respond.
15	type reviewPromptDecorator struct {
16		inner ddxgraphql.ReviewSessionService
17	}
18	
19	// newReviewPromptDecorator wires the structured prompt renderer in front of
20	// the supplied review-session service. If inner is nil the function returns
21	// nil so callers can fall back to the resolver's lazy in-memory default.
22	func newReviewPromptDecorator(inner ddxgraphql.ReviewSessionService) ddxgraphql.ReviewSessionService {
23		if inner == nil {
24			return nil
25		}
26		return &reviewPromptDecorator{inner: inner}
27	}
28	
29	func (d *reviewPromptDecorator) Start(ctx context.Context, input ddxgraphql.ReviewSessionStartInput) (*ddxgraphql.ReviewSession, error) {
30		return d.inner.Start(ctx, input)
31	}
32	
33	func (d *reviewPromptDecorator) Cancel(ctx context.Context, sessionID string) (bool, error) {
34		return d.inner.Cancel(ctx, sessionID)
35	}
36	
37	func (d *reviewPromptDecorator) Subscribe(sessionID string) (<-chan *ddxgraphql.ReviewSessionEvent, func()) {
38		return d.inner.Subscribe(sessionID)
39	}
40	
41	func (d *reviewPromptDecorator) Respond(ctx context.Context, sessionID string, turn ddxgraphql.ReviewTurnInput) (*ddxgraphql.ReviewSession, error) {
42		session, err := d.inner.Respond(ctx, sessionID, turn)
43		if err != nil || session == nil {
44			return session, err
45		}
46		_, _ = RenderReviewPrompt(ReviewPromptRenderInput{
47			Session: serverReviewSessionFromGraphQL(session),
48		})
49		return session, nil
50	}
51	
52	// serverReviewSessionFromGraphQL projects the GraphQL ReviewSession shape into
53	// the server-package ReviewSession used by the prompt renderer. Only the
54	// fields the renderer reads are populated; everything else is left zero.
55	func serverReviewSessionFromGraphQL(in *ddxgraphql.ReviewSession) ReviewSession {
56		out := ReviewSession{
57			ID:          in.ID,
58			ArtifactID:  in.ArtifactID,
59			ArtifactSHA: in.ArtifactSha,
60			Status:      in.Status,
61		}
62		if in.ArtifactGitRev != nil {
63			out.ArtifactGitRev = *in.ArtifactGitRev
64		}
65		if in.SystemRubric != nil {
66			out.SystemRubric = *in.SystemRubric
67		}
68		if in.TemplateRef != nil {
69			out.TemplateRef = *in.TemplateRef
70		}
71		if in.PromptRef != nil {
72			out.PromptRef = *in.PromptRef
73		}
74		for _, t := range in.Turns {
75			if t == nil {
76				continue
77			}
78			out.Turns = append(out.Turns, ReviewTurn{
79				Actor:   t.Actor,
80				Content: t.Content,
81				CostUSD: t.CostUsd,
82			})
83		}
84		return out
85	}
